async def status_cmd(update, context):
    if not context.args:
        return await update.message.reply_text("Use: /status PROJECT_ID")
    pid = context.args[0].strip()
    f = Path(LEAD_DIR, pid + ".json")
    if not f.exists():
        return await update.message.reply_text("❌ Project ID not found.")
    d = json.loads(f.read_text())
    msg = "📌 PROJECT STATUS\n\nID: " + d.get("job_id", pid) + "\nName: " + str(d.get("name","")) + "\nStatus: " + str(d.get("status","pending"))
    await update.message.reply_text(msg)

